import React, { useState, useCallback } from 'react';
import { useDropzone } from 'react-dropzone';
import styled from 'styled-components';
import { Upload, Camera, X, Image as ImageIcon } from 'lucide-react';
import { toast } from 'react-toastify';
import CameraCapture from './CameraCapture';

const UploadContainer = styled.div`
  background: white;
  border-radius: 16px;
  padding: 40px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1);
  text-align: center;
  transition: all 0.3s ease;

  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 12px 40px rgba(0, 0, 0, 0.15);
  }

  @media (max-width: 768px) {
    padding: 30px 20px;
  }
`;

const UploadArea = styled.div`
  border: 3px dashed ${props => props.isDragActive ? '#667eea' : '#e9ecef'};
  border-radius: 12px;
  padding: 60px 20px;
  background: ${props => props.isDragActive ? '#f8f9ff' : '#fafafa'};
  transition: all 0.3s ease;
  cursor: pointer;

  &:hover {
    border-color: #667eea;
    background: #f8f9ff;
  }

  @media (max-width: 768px) {
    padding: 40px 15px;
  }
`;

const UploadIcon = styled.div`
  margin: 0 auto 20px;
  width: 80px;
  height: 80px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-size: 32px;
`;

const UploadText = styled.div`
  font-size: 18px;
  font-weight: 600;
  color: #333;
  margin-bottom: 10px;
`;

const UploadSubtext = styled.div`
  font-size: 14px;
  color: #666;
  margin-bottom: 20px;
`;

const ButtonGroup = styled.div`
  display: flex;
  gap: 15px;
  justify-content: center;
  flex-wrap: wrap;
  margin-top: 20px;
`;

const ActionButton = styled.button`
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 12px 24px;
  border: none;
  border-radius: 8px;
  font-size: 16px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  min-width: 140px;

  &.primary {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;

    &:hover {
      transform: translateY(-2px);
      box-shadow: 0 8px 25px rgba(102, 126, 234, 0.4);
    }
  }

  &.secondary {
    background: #6c757d;
    color: white;

    &:hover {
      background: #5a6268;
      transform: translateY(-2px);
    }
  }
`;

const PreviewContainer = styled.div`
  margin-top: 30px;
  position: relative;
`;

const PreviewImage = styled.img`
  max-width: 100%;
  max-height: 400px;
  border-radius: 12px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.1);
`;

const RemoveButton = styled.button`
  position: absolute;
  top: 10px;
  right: 10px;
  background: rgba(220, 53, 69, 0.9);
  color: white;
  border: none;
  border-radius: 50%;
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.3s ease;

  &:hover {
    background: rgba(220, 53, 69, 1);
    transform: scale(1.1);
  }
`;

const FileInput = styled.input`
  display: none;
`;

const ImageUpload = ({ onImageSelect, onImageRemove, selectedImage }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [showCamera, setShowCamera] = useState(false);

  const onDrop = useCallback((acceptedFiles, rejectedFiles) => {
    if (rejectedFiles.length > 0) {
      toast.error('File không hợp lệ. Vui lòng chọn file ảnh.');
      return;
    }

    if (acceptedFiles.length > 0) {
      const file = acceptedFiles[0];
      if (file.size > 10 * 1024 * 1024) { // 10MB
        toast.error('File quá lớn. Vui lòng chọn file nhỏ hơn 10MB.');
        return;
      }

      setIsLoading(true);
      const reader = new FileReader();
      reader.onload = (e) => {
        onImageSelect(e.target.result, file);
        setIsLoading(false);
        toast.success('Ảnh đã được tải lên thành công!');
      };
      reader.readAsDataURL(file);
    }
  }, [onImageSelect]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: {
      'image/*': ['.jpeg', '.jpg', '.png', '.gif', '.bmp', '.webp']
    },
    multiple: false
  });

  const handleFileSelect = (e) => {
    const file = e.target.files[0];
    if (file) {
      onDrop([file], []);
    }
  };

  const handleCameraClick = () => {
    setShowCamera(true);
  };

  const handleCameraCapture = (imageData, file) => {
    onImageSelect(imageData, file);
    setShowCamera(false);
    toast.success('Ảnh đã được chụp thành công!');
  };

  const handleCameraClose = () => {
    setShowCamera(false);
  };

  return (
    <UploadContainer>
      {!selectedImage ? (
        <>
          <UploadArea {...getRootProps()} isDragActive={isDragActive}>
            <FileInput {...getInputProps()} />
            <UploadIcon>
              <Upload size={40} />
            </UploadIcon>
            <UploadText>
              {isDragActive ? 'Thả ảnh vào đây' : 'Kéo thả ảnh vào đây hoặc click để chọn'}
            </UploadText>
            <UploadSubtext>
              Hỗ trợ: JPG, PNG, GIF, BMP, WEBP (tối đa 10MB)
            </UploadSubtext>
          </UploadArea>

          <ButtonGroup>
            <ActionButton
              type="button"
              className="primary"
              onClick={() => document.getElementById('file-input').click()}
            >
              <ImageIcon size={20} />
              Chọn ảnh
            </ActionButton>

            <ActionButton
              type="button"
              className="secondary"
              onClick={handleCameraClick}
            >
              <Camera size={20} />
              Chụp ảnh
            </ActionButton>
          </ButtonGroup>

          <FileInput
            id="file-input"
            type="file"
            accept="image/*"
            onChange={handleFileSelect}
          />
        </>
      ) : (
        <PreviewContainer>
          <PreviewImage src={selectedImage} alt="Preview" />
          <RemoveButton onClick={onImageRemove}>
            <X size={20} />
          </RemoveButton>
        </PreviewContainer>
      )}

      {isLoading && (
        <div style={{ marginTop: '20px' }}>
          <div className="spinner"></div>
          <p>Đang xử lý ảnh...</p>
        </div>
      )}

      {showCamera && (
        <CameraCapture
          onCapture={handleCameraCapture}
          onClose={handleCameraClose}
        />
      )}
    </UploadContainer>
  );
};

export default ImageUpload;
